import React from 'react';
import { Block } from '../Maps/Base';
import { achievementsStatus } from '../Save/achievements';
import { IfShowInterface } from '../Maps/BaseInterface';
import { EditModeContext } from '../App';

interface Props {
  withGrid: boolean;
  block: Block;
  onBlockClick?: (block:Block) => any;
  isCurrent?: boolean;
  saved?: boolean;
  curAch: achievementsStatus;
  roleX: number;
  roleY: number;
  ifShows: {[index: string]: IfShowInterface};
}
interface State {
  
}
function getBackground(background: string) {
  const back = /url\((.*)\)/.exec(background);
  if (back) {
    return back[1];
  }
}
class MapBlock extends React.Component<Props, State> {
  static isMouseDown = false;
  static currentBlock?: Block = undefined;
  handleBlockClick = (block:Block) => {
    if (this.props.onBlockClick) {
      this.props.onBlockClick(block);
    }
  }
  handleMouseDown = () => {
    MapBlock.isMouseDown = true;
  }
  handleMouseUp = () => {
    MapBlock.isMouseDown = false;
  }
  handleMouseMove = (block:Block) => {
    if (MapBlock.isMouseDown) {
      if (MapBlock.currentBlock !== block) {
        MapBlock.currentBlock = block;
        this.handleBlockClick(block);
      }
    }
  }
  render() {
    const block = this.props.block;
    const withGrid = this.props.withGrid;
    return (
      <EditModeContext.Consumer>
        {value =>
        <div
        className={`block`}
        onClick={()=>this.handleBlockClick(block)}
        onMouseDown={()=>this.handleMouseDown()}
        onMouseUp={()=>this.handleMouseUp()}
        onMouseMove={()=>this.handleMouseMove(block)}
        >
        {block.units.map((unit, index) => {
          let flag = true;
          if (this.props.ifShows && unit.ifShow) {
            const ifShow = this.props.ifShows[unit.ifShow];
            if (ifShow) {
              flag = ifShow({
                roleX: this.props.roleX,
                roleY: this.props.roleY,
                achievements: this.props.curAch,
              })
            }
          }
          if (value || (flag && !(unit.achievement && this.props.curAch[unit.achievement]))) {
              return (
                <div
                  style={{
                    backgroundColor: `${/url.*/.test(unit.background) ? '' : unit.background}`,
                    // backgroundImage: `${/url.*/.test(unit.background) ? unit.background : ''}`,
                    zIndex: unit.zIndex,
                    left: (unit.offsetLeft || undefined)+ 'px',
                    right: (unit.offsetRight|| undefined) + 'px',
                    top: (unit.offsetTop || undefined) + 'px',
                    bottom: (unit.offsetBottom || undefined) + 'px',
                    backgroundSize: 'cover',
                    cursor: unit.click?'pointer':''
                  }}
                  className="unit"
                  key={JSON.stringify(unit) +index}>
                    {getBackground(unit.background)&&<img height={unit.height} width={unit.width} src={getBackground(unit.background)} alt="" />}
                </div>
              )
            } else {
              return <React.Fragment key={index} />
            }
          })}
          {withGrid && <div className="unit __grid">{this.props.children}</div>}
          {this.props.isCurrent && <div className={`unit current-block ${this.props.saved === false ? 'editing' : ''}`}></div>}
      </div>}
      </EditModeContext.Consumer>
    )
  }
}

export default MapBlock;
