export const ifShows: {
  [index: string]: IfShowInterface
} = {
  poster(condition) {
    if (
      condition.roleX === 16
      && condition.roleY ===16
    ) {
      return true;
    }
    return false;
  },
  firstBook(condition) {
    if (
      (condition.achievements && condition.achievements['poster'])
      || (condition.roleX === 16 && condition.roleY === 16)
    ) {
      return false;
    }
    return true;
  },
  advancedEngineerMark(condition) {
    if (condition.achievements && condition.achievements['cet'] && !condition.achievements['advancedEngineer']) {
      return true;
    } else {
      return false;
    }
  },
  cetMark(condition) {
    if (condition.achievements && condition.achievements['poster'] && !condition.achievements['cet']) {
      return true;
    } else {
      return false;
    }
  },
  graduationMark(condition) {
    if (condition.achievements && condition.achievements['advancedEngineer'] && !condition.achievements['graduation']) {
      return true;
    } else {
      return false;
    }
  },
  degreeMark(condition) {
    if (condition.achievements && condition.achievements['advancedEngineer'] && !condition.achievements['degree']) {
      return true;
    } else {
      return false;
    }
  },
  degree(condition) {
    if (
      condition.roleX === 16
      && condition.roleY === 8
    ) {
      return true;
    }
    return false;
  },
  graduation(condition) {
    if (
      condition.roleX === 15
      && condition.roleY === 8
    ) {
      return true;
    }
    return false;
  },
  advancedEngineer(condition) {
    if (
      condition.roleX === 9
      && condition.roleY === 13
    ) {
      return true;
    }
    return false;
  },
  cet(condition) {
    if (
      condition.roleX === 6
      && condition.roleY ===16
    ) {
      return true;
    }
    return false;
  },
  transposrt(condition) {
    if (
      condition.achievements
      && condition.achievements['graduation']
      && condition.achievements['degree']
      && condition.achievements['cet']
      && condition.achievements.advancedEngineer
      && condition.achievements.poster
      ) {
      return true;
    } else {
      return false;
    }
  }
}

