import React from 'react';
import { Unit } from '../../Maps/BaseInterface';

export type AttrList = Array<{
  name: keyof Unit;
  type: string;
  readonly?: boolean;
  values?: any[];
  options?: Array<{name:string,value:any}>;
}>

interface Props {
  unit: Unit;
  attrList: AttrList;
  handleUnitValueChange: (name: keyof Unit, value: any, index: number) => any;
}
interface State {
  
}
class UnitForm extends React.Component<Props, State> {
  handleUnitInputChange = (e:React.ChangeEvent<HTMLInputElement>) => {
    const target = e.target;
    let value: string | boolean | number = target.type === 'checkbox' ? !this.props.unit[target.value as keyof Unit] : target.value;
    const name: keyof Unit = (target.name as keyof Unit);
    const attr = this.props.attrList.find(item => { return item.name === name});
    if (attr && attr.type === 'number') {
      value = Number(value)
    }
    this.props.handleUnitValueChange(name as keyof Unit, value, this.props.unit.index);
  }
  renderInput = (
    type: 'boolean'|'number'|'string'|string,
    name: keyof Unit,
    readonly?:boolean,
    options?:Array<{name:string,value:any}>
  ) => {
    switch(type) {
      case 'boolean':
        return (<input type="checkbox" onChange={this.handleUnitInputChange} name={name} value={name} checked={this.props.unit[name] as boolean} disabled={readonly}></input>)
      default:
        return (
          <React.Fragment>
            <input
              type="text" 
              value={this.props.unit[name] as string || ''}
              disabled={readonly}
              onChange={this.handleUnitInputChange}
              name={name}
              list={name+'list'}
              autoComplete="off"
            >
            </input>
            {options&&<datalist id={name+'list'}>
            {options.map(option => {
              return (
                <option key={option.value} value={option.value}>{option.name}</option>
              )
            })}
          </datalist>}
        </React.Fragment>
        )
    }
  }
  render() {
    return (
      <form>
        {/* {Object.keys(this.props.unit).map(item => {
          return (
            <div>
              <input
                name={item}
                value={this.props.unit[item]}
                onChange={(value)=>this.props.handleUnitValueChange(item,value)}
              ></input>
            </div>
          )
        })} */}
        {this.props.attrList.map(item => {
          return (
            <div key={item.name}>
              <label>
                {item.name}: 
                {this.renderInput(item.type, item.name, item.readonly, item.options)}
              </label>
            </div>
          )
        })}
      </form>
    )
  }
}

export default UnitForm;
