import React from 'react';
import './Zawa.scss';

interface Props {
  
}
interface State {
  x?: number;
  y?: number;
  rotate?: number;
}
class Zawa extends React.Component<Props, State> {
  interval?: number;
  constructor(prop: Props, state: State) {
    super(prop, state);
    this.state = {};
    this.interval = window.setInterval(() => {
      const x = Math.random() * 100;
      const y = Math.random() * 100;
      const rotate = Math.random() * 90;
      this.setState({
        x, y, rotate,
      });
    }, 2000);
  }
  componentWillUnmount() {
    window.clearInterval(this.interval);
  }
  render() {
    return (
      <div className="zawa" style={{
        left: this.state.x + '%',
        top: this.state.y + '%',
        transform: `rotate(${this.state.rotate}deg)`
      }}>ざわ..</div>
    )
  }
}

export default Zawa;
