export const ifShows: {
  [index: string]: IfShowInterface
} = {
  dotNet(condition) {
    if (
      condition.achievements && (!condition.achievements['dotNet'])
      && condition.roleX === 9
      && condition.roleY === 3
    ) {
      return true;
    }
    return false;
  },
  react(condition) {
    if (
      condition.achievements && (!condition.achievements['react'])
      && condition.roleY! > 8
    ) {
      return true;
    }
    return false;
  },
  vue(condition) {
    if (
      condition.achievements && (!condition.achievements['vue'])
      && condition.roleX === 8
      && condition.roleY === 6
    ) {
      return true;
    }
    return false;
  },
  angular(condition) {
    if (
      condition.achievements && (!condition.achievements['angular'])
      && condition.roleX === 17
      && condition.roleY === 6
    ) {
      return true;
    }
    return false;
  },
  cordorva(condition) {
    if (
      condition.achievements && (!condition.achievements['cordova'])
      && condition.roleX === 14
      && condition.roleY === 3
    ) {
      return true;
    }
    return false;
  },
  ts(condition) {
    if (
      condition.achievements && (!condition.achievements['ts'])
      && condition.roleX === 16
      && condition.roleY ===16
    ) {
      return true;
    }
    return false;
  },
  firstWall(condition) {
    if (
      !(condition.roleX === 6
      && condition.roleY === 6)
    ) {
      return true;
    }
    return false;
  },
  firstGate(condition) {
    if (condition.achievements&&condition.achievements['vue']) {
      return false;
    }
    return true;
  },
  secondGate(condition) {
    if (condition.achievements&&condition.achievements['react']) {
      return false;
    }
    return true;
  },
}

