import React from 'react';
import { Block } from '../../Maps/Base';
import { MapFrame, Unit } from '../../Maps/BaseInterface';
import UnitForm, { AttrList } from './UnitForm';
import './Right.scss';

interface Props {
  blockInfo?: Block;
  mapInfo: MapFrame;
  editBlock: (block: Block) => any;
  resetBlock: () => void;
  saveChanges: () => void;
  events: string[];
  ifShows: string[];
}
interface State {
  // unitForm: Unit;
  attrList: AttrList;
}

const attrList: AttrList = [
  {name: 'background', type: 'string'},
  {name: 'height', type: 'string'},
  {name: 'width', type: 'string'},
  {name: 'offsetLeft', type: 'number'},
  {name: 'offsetTop', type: 'number'},
  {name: 'offsetRight', type: 'number'},
  {name: 'offsetBottom', type: 'number'},
  {name: 'blocked', type: 'boolean'},
  {name: 'zIndex', type: 'number'},
  {name: 'moveOn', type: 'string'},
  {name: 'click', type: 'string'},
  {name: 'achievement', type: 'string' },
  {name: 'ifShow', type: 'string'},
]

class Right extends React.Component<Props, State> {
  // private _block: Block | undefined;
  eventOptions = {
    value: [],
  }
  constructor(props: Props, state: State) {
    super(props, state);
    // this._block = props.blockInfo;
    this.state = {
      attrList: attrList,
    }
  }
  static getDerivedStateFromProps(props: Props, state: State): State {
    const events = props.events.map(item => {
      return {
        name: item,
        value: item,
      }
    })
    const ifShows = props.ifShows.map(item => {
      return {
        name: item,
        value: item,
      }
    })
    state.attrList.find(item => item.name === 'click')!.options = events
    state.attrList.find(item => item.name === 'moveOn')!.options = events
    state.attrList.find(item => item.name === 'ifShow')!.options = ifShows
    return {
      attrList: state.attrList
    }
  }
  handleUnitDelete = (unit: Unit) => {
    let block = this.props.blockInfo;
    if (block) {
      // delete block.units[unit.index];
      let index = block.units.indexOf(unit);
      block.units.splice(index, 1);
      if (block.units.length === 0) {
        block.blocked = true;
      }
      this.props.editBlock(block);
    }
  }
  handleUnitValueChange = (name: keyof Unit, value: any, index: number) => {
    let _block = this.props.blockInfo;
    if (_block) {
      const _unit = _block.units.find((item) => {
        return item.index === index;
      });
      if (_unit) {
        switch(name) {
          case 'background':
            _unit[name] = value;
            break;
          case 'offsetLeft':
          case 'offsetTop':
          case 'offsetRight':
          case 'offsetBottom':
            _unit[name] = value;
            break;
          case 'zIndex':
            _unit[name] = value;
            break;
          case 'moveOn':
            _unit[name] = value;
            break;
          case 'click':
            _unit[name] = value;
            break;
          case 'ifShow':
            _unit[name] = value;
            break;
          case 'achievement':
            _unit[name] = value;
            break;
          case 'blocked':
            _unit[name] = value;
            break;
        }
        // console.log(_unit)
        this.props.editBlock(_block);
      }
    }
  }
  resetBlock = () => {
    this.props.resetBlock();
  }
  render() {
    return (
      <div className="editor-right">
        {this.props.blockInfo&&<fieldset>
          <legend>BlockInfo</legend>
          <fieldset>
            <legend>BaseInfo</legend>
            <div>
              <span>index: {this.props.mapInfo.columnCount * this.props.blockInfo.row + this.props.blockInfo.column}; </span>
              <span>row: {this.props.blockInfo.row}; </span>
              <span>column: {this.props.blockInfo.column}; </span>
              <span>blocked: {this.props.blockInfo.blocked.toString()}; </span>
            </div>
          </fieldset>
          <fieldset>
            <legend>Units</legend>
            {this.props.blockInfo.units.map((item, index) => {
              return (
                <div key={index}>
                  <span>{index}: </span>
                  {/* <span>{JSON.stringify(item)}</span> */}
                  <UnitForm
                    attrList={attrList}
                    unit={item}
                    handleUnitValueChange={this.handleUnitValueChange}
                  ></UnitForm>
                  <button onClick={() => {this.handleUnitDelete(item)}}>delete</button>
                </div>
              )
            })}
          </fieldset>
          <fieldset>
            <button onClick={this.resetBlock}>reset</button>
            {/* <button onClick={this.props.saveChanges}>save</button> */}
          </fieldset>
        </fieldset>}
      </div>
    )
  }
}

export default Right;
