export default {
  set(key: string, value: any) {
    try {
      const _value = JSON.stringify(value);
      localStorage.setItem(key, _value);
    } catch (err) {
      console.error(err);
    }
  },
  get(key: 'achievements') {
    try {
      const _value = localStorage.getItem(key);
      if (!_value) {
        return null;
      }
      return JSON.parse(_value);
    } catch(err) {
      console.error(err);
    }
  }
}