import React from 'react';
import './Dialog.scss';

interface Props {
  changeVisiable: (flag?:boolean) => void;
  visiable: boolean;
}
interface State {
  
}
class Dialog extends React.Component<Props, State> {
  render() {
    return (
      <div
        className="dialog" onClick={()=>this.props.changeVisiable()}
        style={{top: this.props.visiable?'0':'-100%'}}>
        {this.props.visiable&&<div className="content">{this.props.children}</div>}
      </div>
    )
  }
}

export default Dialog;
