import React, { useState } from 'react';
// import logo from './logo.svg';
import './App.css';
// import MapView from './Views/Map';
import Editor from './Views/Editor/Editor';
import PlayMode from './Views/PlayMode';

export const EditModeContext = React.createContext(true);

const App: React.FC = () => {
  const [editMode, changeMode] = useState(false);
  const [saveData, changeSaveData] = useState({});
  const SaveDataContext = React.createContext({});
  return (
    <SaveDataContext.Provider value={{saveData, changeSaveData}}>
      <EditModeContext.Provider value={editMode}>
        <div id="app">
          {/* <MapView></MapView> */}
          <button
            className="mode-button"
            onClick={() => {changeMode(!editMode)}}
            style={{display:process.env.NODE_ENV==='development'?'block':'none'}}
          >{editMode?'play':'edit'}</button>
          {
            process.env.NODE_ENV === 'development' ?
            editMode ?
            <Editor></Editor> :
            <PlayMode></PlayMode>
            : <PlayMode></PlayMode>
          }
        </div>
      </EditModeContext.Provider>
    </SaveDataContext.Provider>
  );
}

export default App;
