import React from 'react';
import './Left.scss';
import UNITS from './Units';
import { Unit, MapFrame } from '../../Maps/BaseInterface';

interface State {
  curUnit: Omit<Unit, 'index'>;
}
interface Props {
  rowCount: number;
  columnCount: number;
  grid: boolean;
  showNum: boolean;
  currentUnit: string;
  currentMode?: string;
  exportedRes?: string;
  handleGridChange: (e:React.ChangeEvent<HTMLInputElement>)=>void;
  handleShowNumChange: (e:React.ChangeEvent<HTMLInputElement>)=>void;
  handleCurrentUnitChange: (unit: {name: string, unit: Omit<Unit, 'index'>} | undefined)=>void;
  handleColumnCountChange: (e:React.ChangeEvent<HTMLInputElement>)=>void;
  handleRowCountChange: (e:React.ChangeEvent<HTMLInputElement>)=>void;
  commitCountChange: () => void;
  pushButtonClick: () => void;
  exportMap: ()=>void;
  resetMap: () => void;
  saveChanges: () => void;
  maps: MapFrame[];
  brushMode: boolean;
  handleMapChange: (map: MapFrame, events:string[], ifShows:string[]) => void;
  changeBrushMode: (mode: boolean) => void;
  events: string[][];
  ifShows: string[][];
}
function getBackground(background: string) {
  const back = /url\((.*)\)/.exec(background);
  if (back) {
    return back[1];
  }
}
class Left extends React.Component<Props, State> {
  constructor(props:Props, state:State) {
    super(props, state);
    this.state = {
      curUnit: UNITS[0].unit,
    }
  }
  handlePushButtonClick = () => {
    this.props.pushButtonClick();
  }
  handleUnitChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const unit = UNITS.find((item) => {
      return item.name === e.target.value;
    })
    if (unit) {
      this.setState({
        curUnit: unit.unit,
      });
    }
    this.props.handleCurrentUnitChange(unit);
  }
  handleMapChange = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const index = e.currentTarget.value;
    this.props.handleMapChange(
      this.props.maps[Number(index)],
      this.props.events[Number(index)],
      this.props.ifShows[Number(index)],
    )
  }
  handleChangeBrushMode = () => {
    this.props.changeBrushMode(!this.props.brushMode);
  }
  render() {
    return <React.Fragment>
      <fieldset>
        <legend></legend>
        <label className="row">
          map
          <select onChange={this.handleMapChange}>
            {this.props.maps.map((item, index) => {
              return (<option value={index} key={item.name}>{item.name}</option>)
            })}
          </select>
        </label>
      </fieldset>
      <fieldset>
        <legend>Config</legend>
        <label className="row">
          grid
          <input type="checkbox" name="grid" value="grid" 
            checked={this.props.grid}
            onChange={this.props.handleGridChange}
            />
        </label>
        <label className="row">
          num
          <input type="checkbox" name="showNum" value="showNum" 
            checked={this.props.showNum}
            onChange={this.props.handleShowNumChange}
            />
        </label>
      </fieldset>
      <fieldset>
        <legend>Sets</legend>
        <label className="row">
          rowCount:
          <input type="text"
            value={this.props.rowCount}
            onChange={this.props.handleRowCountChange}></input>
        </label>
        <label className="row">
          columnCount:
          <input type="text"
            value={this.props.columnCount}
            onChange={this.props.handleColumnCountChange}></input>
        </label>
        <button onClick={this.props.commitCountChange}>commit</button>
        <div className="row">
          <span>BlockType: </span>
          {/* <label>
            plain
            <input type="radio" name="unit" value="plain" 
              checked={this.props.currentUnit === 'plain'}
              onChange={this.props.handleCurrentUnitChange}
              />
          </label>
          <label>
            wall
            <input type="radio" name="unit" value="wall" 
              checked={this.props.currentUnit === 'wall'}
              onChange={this.props.handleCurrentUnitChange}
              />
          </label> */}
          <select onChange={this.handleUnitChange}>
            {UNITS.map(item => {
              return <option value={item.name} key={item.name}>{item.name}</option>
            })}
          </select>
          <button onClick={this.handlePushButtonClick}>push</button>
          <button onClick={this.handleChangeBrushMode}>{this.props.brushMode?'brush':'click'}</button>
          <div
            style={{
              height: '30px',
              width: '30px',
              backgroundColor: `${/url.*/.test(this.state.curUnit.background) ? '' : this.state.curUnit.background}`,
              // backgroundImage: `${/url.*/.test(unit.background) ? unit.background : ''}`,
              zIndex: this.state.curUnit.zIndex,
              backgroundSize: 'cover',
              cursor: this.state.curUnit.click?'pointer':''
            }}
            className="unit"
            >
              {getBackground(this.state.curUnit.background)&&<img src={getBackground(this.state.curUnit.background)} alt="" />}
          </div>
        </div>
      </fieldset>
      <fieldset>
        <button onClick={()=>{this.props.resetMap()}}>ResetMap</button>
        <button onClick={()=>{this.props.saveChanges()}}>SaveMap</button>
        <button onClick={()=>{this.props.exportMap()}}>Export</button>
      </fieldset>
      <fieldset>
        <textarea style={{width:'100%',height:'200px'}} value={this.props.exportedRes}></textarea>
      </fieldset>
    </React.Fragment>
  }
}

export default Left;
