import React from 'react';
import './Toast.scss';

interface Props {
  text: string;
  changeStatus: (status: boolean) => void;
  callBack?: () => any;
}
interface State {
  
}
class Toast extends React.Component<Props, State> {
  handleBubbleClick = () => {
    this.props.changeStatus(false)
    this.forceUpdate()
    if (this.props.callBack) {
      this.props.callBack();
    }
  }
  render() {
    return (
      <div className="toast">
        <div className="bubble" onClick={() => this.handleBubbleClick()}>
          {this.props.text.split('').map((item, index) => {
            return <div className="font" key={item+index} style={{
              animationDelay: `${index*0.05}s`
            }}>{item}</div>
          })}
          <span className="caret"></span>
        </div>
      </div>
    )
  }
}

export default Toast;
