export function saveAchievements(ach: achievementsStatus) {
  const curAch = getAchievements();
  Object.assign(curAch, ach);
  localSave.set('achievements', curAch);
}

export function getAchievements(): achievementsStatus {
  return localSave.get('achievements') || {};
}

export function clearSaveData() {
  localSave.set('achievements', {});
}
