import React, { SyntheticEvent } from 'react';
import * as MapInterface from '../../Maps/BaseInterface';
import Map from '../Map';
import { Block } from '../../Maps/Base';
import './Editor.scss';
import Left from './Left';
import Right from './Right';
import { deepCopy } from '../../utils/tools';
import UNITS from './Units';
// import {MAPS} from '../CONFIG';
// import { cloneDeep } from 'lodash';

interface State {
  currentUnit: string;
  unitTarget: Omit<MapInterface.Unit, 'index'>;
  currentMode?: string;
  rowCount: number;
  columnCount: number;
  mapRes: MapInterface.MapFrame;
  curEvents: string[];
  curIfShows: string[];
  grid: boolean;
  showNum: boolean;
  blocks: Block[];
  currentBlock?: Block;
  mapOffsetX: number;
  mapOffsetY: number;
  saved: boolean;
  maps: MapInterface.MapFrame[];
  exportedRes?: string;
  brushMode: boolean;
  events: string[][];
  ifShows: string[][];
}

class Editor extends React.Component<{}, State> {
  state: State;
  _block?: Block;
  _mapRes?: MapInterface.MapFrame;
  ref: React.RefObject<Map> = React.createRef();
  constructor(props: {}, state: State) {
    super(props, state);
    const blocks: Block[] = [];
    const rowCount = 23;
    const columnCount = 23;
    for (let row = 0; row < rowCount; ++ row) {
      for (let col = 0; col < columnCount; ++col) {
        blocks.push({
          index: row * columnCount + col,
          row: row,
          column: col,
          blocked: false,
          units: [{
            index: 0,
            type: 'default',
            background: 'green',
            blocked: false,
            zIndex: 1
          }]
        })
      }
    }
    const mapRes = {
      name: 'newMap',
      rowCount: rowCount,
      columnCount: columnCount,
      blocks: blocks
    }
    const maps: MapInterface.MapFrame[] = [
      mapRes,
      require('../../Maps/res/plain1').map,
      require('../../Maps/res/school').map,
      require('../../Maps/res/underground').map,
    ];
    const events: string[][] = [
      {},
      require('../../Maps/res/plain1').events || {},
      require('../../Maps/res/school').events || {},
      require('../../Maps/res/underground').events || {},
    ].map(item => Object.keys(item))
    const ifShows: string[][] = [
      {},
      require('../../Maps/res/plain1').ifShows || {},
      require('../../Maps/res/school').ifShows || {},
      require('../../Maps/res/underground').ifShows || {},
    ].map(item => Object.keys(item))
    this._mapRes = deepCopy(mapRes);
    this.state = {
      mapOffsetX: 0,
      mapOffsetY: 0,
      unitTarget: UNITS[0].unit,
      rowCount,
      columnCount,
      mapRes: mapRes,
      grid: true,
      showNum: false,
      blocks: blocks,
      currentUnit: 'plain',
      saved: true,
      maps: maps,
      brushMode: false,
      events: events,
      ifShows,
      curEvents: [],
      curIfShows: [],
    }
  }
  handleMapChange = (map: MapInterface.MapFrame, events: string[], ifShows: string[]) => {
    this._mapRes = deepCopy(map);
    this.setState({
      mapRes: map,
      rowCount: map.rowCount,
      columnCount: map.columnCount,
      curEvents: events,
      curIfShows: ifShows,
    });
  }
  handleCurrentUnitChange = (unit?: {name: string, unit: Omit<MapInterface.Unit, 'index'>}) => {
    // const value = e.target.value;
    // let unit: Omit<MapInterface.Unit, 'index'>;
    // switch(value) {
    //   case 'plain':
    //     unit = {
    //       background: 'lightgreen',
    //       blocked: false,
    //       type: 'plain',
    //       zIndex: 1
    //     }
    //   break;
    //   case 'wall':
    //     unit = {
    //       background: 'gray',
    //       blocked: true,
    //       type: 'wall',
    //       zIndex: 1
    //     }
    //   break;
    //   default:
    //     unit = {
    //       background: 'transparent',
    //       blocked: true,
    //       type: 'empty',
    //       zIndex: 1
    //     }
    // }
    // this.setState({
    //   currentUnit: value,
    //   unitTarget: unit
    // })
    if (unit) {
      this.setState({
        unitTarget: unit.unit
      })
    }
  }
  commitCountChang = () => {
    this.setState((state) => {
      let mapRes = state.mapRes;
      const rowCount = state.rowCount;
      const columnCount = state.columnCount;
      let blocks = [];
      for (let row = 0; row < rowCount; ++ row) {
        for (let col = 0; col < columnCount; ++col) {
          blocks.push({
            index: row * columnCount + col,
            row: row,
            column: col,
            blocked: false,
            units: [{
              index: 0,
              type: 'default',
              background: 'green',
              blocked: false,
              zIndex: 1
            }]
          })
        }
      }
      mapRes.rowCount = rowCount;
      mapRes.columnCount = columnCount;
      mapRes.blocks = blocks;
      return {
        mapRes
      }
    })
  }
  handleRowCountChange = (e:React.ChangeEvent<HTMLInputElement>) => {
    const value = Number(e.target.value);
    if (!Number.isNaN(value)) {
      this.setState((state) => {
        return {
          rowCount: value,
        }
      })
    }
  }
  handleColumnCountChange = (e:React.ChangeEvent<HTMLInputElement>) => {
    const value = Number(e.target.value);
    if (!Number.isNaN(value)) {
      this.setState((state) => {
        return {
          columnCount: value,
        }
      })
    }
  }
  handleGridChange = (e:React.ChangeEvent<HTMLInputElement>) => {
    this.setState({grid: !this.state.grid})
  }
  handleShowNumChange = (e:React.ChangeEvent<HTMLInputElement>) => {
    this.setState({showNum: !this.state.showNum})
  }
  handleMapClick(e:SyntheticEvent) {
    console.log(e)
    console.log(e.currentTarget)
    console.log(e.target)
  }
  changeBrushMode = (mode: boolean) => {
    this.setState({
      brushMode: mode,
    });
  }
  handleBlockClick(block:Block) {
    // if (!this.state.saved) {
    //   alert('save or reset your changes');
    //   return;
    // }
    this._block = deepCopy(block);
    // this._block = cloneDeep(block);
    this.setState({
      currentBlock: block
    }, () => {
      if (this.state.brushMode) {
        const unitTarget = this.state.unitTarget;
        const currentBlock = this.state.currentBlock;
        if (currentBlock && unitTarget) {
          this.setState({
            saved: false
          });
          const lastUnit = currentBlock.units[currentBlock.units.length - 1];
          this.setState((state) => {
            const mapRes = this.state.mapRes;
            currentBlock.units.push({
              ...unitTarget,
              index: lastUnit ? lastUnit.index + 1 : 0,
              zIndex: lastUnit ? lastUnit.zIndex + 1 : 0,
            });
            currentBlock.blocked = currentBlock.units.some(item => {
              return item.blocked
            })
            mapRes.blocks[currentBlock.row * mapRes.columnCount + currentBlock.column]
            = currentBlock;
            return {
              mapRes
            }
          })
        }
      }
    })
  }
  editBlock = (block: Block) => {
    this.setState({
      saved: false
    });
    this.setState((state) => {
      const mapRes = state.mapRes;
      mapRes.blocks[block.index] = block;
      return {mapRes}
    })
  }
  resetBlock = () => {
    this.setState((state) => {
      const mapRes = state.mapRes;
      if (this._block) {
        mapRes.blocks[this._block.index] = deepCopy(this._block);
        return {
          mapRes,
          currentBlock: deepCopy(this._block),
        }
      }
      return {
        mapRes,
        currentBlock: undefined,
      }
    }, () => {
      this.setState({
        saved: true
      });
    })
  }
  resetMap = () => {
    if (this._mapRes) {
      this.setState({mapRes: deepCopy(this._mapRes)}, () => {
        const _block = this.state.currentBlock;
        if (_block) {
          this._block = _block;
          this.setState({
            currentBlock: this.state.mapRes.blocks[_block.index],
            saved: true,
          })
        }
      })
    }
  }
  pushButtonClick = () => {
    const unitTarget = this.state.unitTarget;
    const currentBlock = this.state.currentBlock;
    if (currentBlock && unitTarget) {
      this.setState({
        saved: false
      });
      const lastUnit = currentBlock.units[currentBlock.units.length - 1];
      console.log(unitTarget)
      this.setState((state) => {
        const mapRes = this.state.mapRes;
        currentBlock.units.push({
          ...unitTarget,
          index: lastUnit ? lastUnit.index + 1 : 0,
          zIndex: unitTarget.zIndex || (lastUnit ? lastUnit.zIndex + 1 : 0),
        });
        currentBlock.blocked = currentBlock.units.some(item => {
          return item.blocked
        })
        mapRes.blocks[currentBlock.row * mapRes.columnCount + currentBlock.column]
        = currentBlock;
        return {
          mapRes
        }
      })
    }
  }
  handleMapPostionClick = (direct:string) => {
    // if (this.ref.current) {
    //   this.ref.current.handleMapPostionClick(direct);
    // }
    switch(direct) {
      case 'up':
        this.setState((state) => {
          return {mapOffsetY: state.mapOffsetY - 1}
        })
      break;
      case 'down':
        this.setState((state) => {
          return {mapOffsetY: state.mapOffsetY + 1}
        })
      break;
      case 'left':
        this.setState((state) => {
          return {mapOffsetX: state.mapOffsetX - 1}
        })
      break;
      case 'right':
        this.setState((state) => {
          return {mapOffsetX: state.mapOffsetX + 1}
        })
      break;
    }
  }
  saveChanges = () => {
    this._mapRes = deepCopy(this.state.mapRes);
    this.setState({
      saved: true
    });
  }
  render() {
    return (
      <div id="editor">
        <div id="left">
          <Left
            pushButtonClick={this.pushButtonClick}
            columnCount={this.state.columnCount}
            rowCount={this.state.rowCount}
            currentMode={this.state.currentMode}
            currentUnit={this.state.currentUnit}
            grid={this.state.grid}
            showNum={this.state.showNum}
            handleColumnCountChange={this.handleColumnCountChange}
            handleCurrentUnitChange={this.handleCurrentUnitChange}
            handleGridChange={this.handleGridChange}
            handleShowNumChange={this.handleShowNumChange}
            handleRowCountChange={this.handleRowCountChange}
            commitCountChange={this.commitCountChang}
            exportedRes={this.state.exportedRes}
            brushMode={this.state.brushMode}
            changeBrushMode={this.changeBrushMode}
            exportMap={()=>{
              const res = "import {MapFrame} from '../../BaseInterface';\nexport const _map: MapFrame =\n" + JSON.stringify(this.state.mapRes,null,2);
              this.setState({
                exportedRes: res,
              })
            }}
            resetMap={this.resetMap}
            saveChanges={this.saveChanges}
            maps={this.state.maps}
            handleMapChange={this.handleMapChange}
            events={this.state.events}
            ifShows={this.state.ifShows}
            >
          </Left>
        </div>
        <div id="middle">
          <button className="map-up" onClick={()=>this.handleMapPostionClick('up')}>↑</button>
          <div className="center-wrapper">
            <button className="map-left" onClick={()=>this.handleMapPostionClick('left')}>←</button>
            <Map
              mapOffsetX={this.state.mapOffsetX}
              mapOffsetY={this.state.mapOffsetY}
              withGrid={this.state.grid}
              onBlockClick={(block)=>{this.handleBlockClick(block)}}
              mapData={this.state.mapRes}
              currentBlock={this.state.currentBlock}
              saved={this.state.saved}
              ref={this.ref}
              showNum={this.state.showNum}></Map>
            <button className="map-right" onClick={()=>this.handleMapPostionClick('right')}>→</button>
          </div>
          <button className="map-down" onClick={()=>this.handleMapPostionClick('down')}>↓</button>
        </div>
        <div id="right">
          <Right
            mapInfo={this.state.mapRes}
            blockInfo={this.state.currentBlock}
            editBlock={this.editBlock}
            resetBlock={this.resetBlock}
            saveChanges={this.saveChanges}
            events={this.state.curEvents}
            ifShows={this.state.curIfShows}
          ></Right>
        </div>
      </div>
    )
  }
}

export default Editor;
