import React, { ReactNode } from 'react';
import * as MapBaseInterface from '../Maps/BaseInterface';
import './Map.scss';
import Round from './Figure/Round';
import { Block } from '../Maps/Base';
import MapBlock from './MapBlock';
import CONFIG from './CONFIG';
import RoundFigure from './Figure/Round';
import { getAchievements, achievementsStatus } from '../Save/achievements';
import { IfShowInterface } from '../Maps/BaseInterface';
import Toast from './Toast';
import { EditModeContext } from '../App';
import Dialog from './Dialog';

let onBlockClick: ((block:Block)=>void)|undefined;

function printRow(
  curAch: achievementsStatus,
  map: MapBaseInterface.MapFrame,
  withGrid = false,
  figureX: number,
  figureY: number,
  ifShows: {[index: string]: IfShowInterface},
  currentBlock?:Block,
  showNum?: boolean,
  saved?: boolean) {
  const res = [];
  // const length = map.columnCount * map.rowCount;
  for (let i = 0; i < map.rowCount; ++i) {
    const row = [];
    for (let c = 0; c < map.columnCount; ++c) {
      const block = map.blocks[c + i * map.columnCount];
      row.push(
        // printBlock(map.blocks[c + i * map.columnCount], withGrid)
        <MapBlock
          block={block}
          withGrid={withGrid}
          onBlockClick={onBlockClick}
          key={block.column * map.columnCount + block.row}
          isCurrent={currentBlock&&currentBlock.row===block.row&&currentBlock.column===block.column}
          saved={saved}
          curAch={curAch}
          roleX={figureX}
          roleY={figureY}
          ifShows={ifShows}
      >{showNum&&<span className="block-num">{block.index}</span>}</MapBlock>
      )
    }
    res.push(
      <div className={`row`} key={i}>
        {row}
      </div>
    );
  }
  return res;
}

interface Props {
  withGrid?: boolean,
  onBlockClick?:(block:Block)=>void,
  mapData: MapBaseInterface.MapFrame,
  currentBlock?: Block;
  mapOffsetX?: number,
  mapOffsetY?: number,
  saved?: boolean,
  showNum?: boolean,
  ifShows?: {[index: string]: IfShowInterface},
  toastText?: string;
  showToast?: boolean;
  mapCover?: string;
  mapBack?: string;
  toastCallBack?: () => any;
  changeToastStatus?: (status: boolean) => void;
  events?: {
    [index:string]: {
      type: string;
      action: ()=>any;
    }
  },
  figureX?: number,
  figureY?: number,
  moving?: boolean,
  face?: 'left' | 'right' | 'front' | 'back',
  hurt?: boolean,
}
interface State {
  figureX: number,
  figureY: number,
  moving: boolean,
  mapOffsetX: number,
  mapOffsetY: number,
  face: 'left' | 'right' | 'front' | 'back',
  hurt: boolean,
  dialogContent?: ReactNode,
  dialogVisiable: boolean,
}

export default class MapView extends React.Component<Props, State> {
  moving = false;
  curKey: string | null = null;
  moveBoundle: (() => void) | null | 'busy' = null;
  curBoundleKey: string | null = null;
  mapMoveXCount: number = 0;
  mapMoveYCount: number = 0;
  constructor(props: Props, state: State) {
    super(props, state)
    onBlockClick = props.onBlockClick;
    this.state = {
      figureX: 10,
      figureY: 10,
      moving: false,
      mapOffsetX: 0,
      mapOffsetY: 0,
      face: 'front',
      hurt: false,
      dialogVisiable: false,
    }
  }
  roundHurt = () => {
    this.setState({hurt: true}, () => {
      setTimeout(() => {
        this.setState({hurt: false})
      }, 1000);
    })
  }
  showDialog = (content: ReactNode) => {
    this.setState({
      dialogContent: content,
      dialogVisiable: true,
    })
  }
  changeDialogVisiable = (flag?: boolean) => {
    if (typeof(flag) === 'boolean') {
      this.setState({
        dialogVisiable: flag,
      })
    } else {
      this.setState((state) => {
        return {
          dialogVisiable: !state.dialogVisiable,
        }
      })
    }
  }
  handleMapPostionClick = (direct:string) => {
    switch(direct) {
      case 'up':
        this.setState((state) => {
          return {mapOffsetY: state.mapOffsetY - 1}
        })
      break;
      case 'down':
        this.setState((state) => {
          return {mapOffsetY: state.mapOffsetY + 1}
        })
      break;
      case 'left':
        this.setState((state) => {
          return {mapOffsetX: state.mapOffsetX - 1}
        })
      break;
      case 'right':
        this.setState((state) => {
          return {mapOffsetX: state.mapOffsetX + 1}
        })
      break;
    }
  }
  hurtRef = (hurt: () => void) => {
    this.hurtRef = hurt;
  }
  ref =  React.createRef<RoundFigure>();
  render() {
    const achievements = getAchievements();
    return (
      <EditModeContext.Consumer>{ value =>
        <div id="map">
          {/* <div style={{position:'absolute',left:0,top:0,color:'black'}}>{JSON.stringify(this.context)}</div> */}
          {this.props.mapCover&&<div id="map-cover" style={{background: this.props.mapCover}}></div>}
          {this.props.mapBack&&<div id="map-back" style={{background: this.props.mapBack}}></div>}
          <div id="full-map" style={{
            left: this.props.mapOffsetX && this.props.mapOffsetX * CONFIG.BLOCK_SIZE,
            top: this.props.mapOffsetY && this.props.mapOffsetY * CONFIG.BLOCK_SIZE,
          }}>
            <Round
              onclick={this.roundHurt}
              animated={this.props.moving}
              x={this.props.figureX !== undefined ? this.props.figureX : -1}
              y={this.props.figureY !== undefined ? this.props.figureY : -1}
              face={this.props.face}
              hurtRef={this.hurtRef}
              ref={this.ref}
              hurt={this.props.hurt}></Round>
            {printRow(achievements, this.props.mapData, this.props.withGrid, this.props.figureX!, this.props.figureY!, this.props.ifShows!, this.props.currentBlock, this.props.showNum, this.props.saved)}
          </div>
          {<Dialog
            changeVisiable={this.changeDialogVisiable}
            visiable={this.state.dialogVisiable}>
            {this.state.dialogContent}
          </Dialog>}
          {(!value&&this.props.showToast)&&<Toast callBack={this.props.toastCallBack} changeStatus={this.props.changeToastStatus!} text={this.props.toastText||''} />}
        </div>
      }</EditModeContext.Consumer>
    )
  }
}