import React from 'react';
import './Round.scss';
import CONFIG from '../CONFIG';
import EVENTS from '../../utils/EVENTS';
// import round from './round/main.svg';
// import hurt from './round/hurt.svg';

interface Props {
  x: number;
  y: number;
  animated: boolean;
  hurtRef?: (hurt:()=>void) => void;
  face?: 'left' | 'right' | 'back' | 'front';
  hurt: boolean;
  onclick: () => void;
}

interface State {
  status: string;
  hurt?: boolean;
  showShadow?: boolean;
  figureTop?: string;
  figureTransition?: string;
}

const faceAttr = {
  left: {
    rotateY: 70,
    translateX: 50
  },
  right: {
    rotateY: 70,
    translateX: 150
  },
  back: {
    rotateY: 180,
    translateX: 0,
  },
  front: {
    rotateY: 0,
    translateX: 0,
  }
}

class RoundFigure extends React.Component<Props, State> {
  static defaultProps = {
    animated: false,
    face: 'front',
    hurt: false,
  }
  dummy: number = 0;
  constructor(props: Props, state: State) {
    super(props, state);
    if (this.props.hurtRef) {
      this.props.hurtRef(this.hurtAnimate);
    }
    this.state = {
      status: '',
      hurt: false,
      showShadow: true,
    }
    EVENTS.hurt = this.hurtAnimate;
  }
  hurtAnimate = () => {
    this.setState({hurt: true}, () => {
      setTimeout(() => {
        this.setState({hurt: false})
      }, 1500);
    })
  }
  disableWsad = () => {
    const backup = document.onkeydown;
    document.onkeydown = null;
    window.setTimeout(() => {
      document.onkeydown = backup;
    }, 4000);
  }
  dropDown = () => {
    setTimeout(() => {
      this.setState({
        showShadow: false,
        figureTop: '-600px',
        figureTransition: 'top 0.5s ease-out',
        hurt: true,
      }, () => {
        this.disableWsad();
        setTimeout(() => {
          this.setState({
            showShadow: true,
            // hurt: false,
            figureTop: undefined,
            // figureTransition: undefined,
          }, () => {
            setTimeout(() => {
              this.setState({
                hurt: false,
                figureTransition: undefined,
              })
            }, 2000);
          })
        }, 2000);
      });
    }, 2000);
  }
  render() {
    if (this.props.animated) {
      this.dummy++;
    }
    return(
      // <div
      //   id="figure"
      //   style={{
      //     left: `${this.props.x * CONFIG.BLOCK_SIZE}px`,
      //     top: `${this.props.y * CONFIG.BLOCK_SIZE}px`,
      //   }}
      //   >
      //   <div
      //     className={`run${this.dummy % 2} round`}
      //   >
      //   </div>
      //   <div
      //     className={`run${this.dummy % 2} shadow`}
      //   ></div>
      // </div>
      <div
        id="figure"
        onClick={() => {console.log('aaa');this.props.onclick()}}
        style={{
          left: `${this.props.x * CONFIG.BLOCK_SIZE}px`,
          top: `${this.props.y * CONFIG.BLOCK_SIZE}px`,
        }}>
        <svg width="30" height="30" version="1.1"
          xmlns="http://www.w3.org/2000/svg"
          className={`round run${this.dummy % 2}`}
          style={{
            top: this.state.figureTop,
            transition: this.state.figureTransition,
          }}>
          <defs>
            <filter id="shadow" width="200%" height="200%">
              <feDropShadow dx="2" dy="2" stdDeviation="1" floodColor="gray" transform="scale=(1 0.2)" />
            </filter>
          </defs>
          <circle r="8" cx="15" cy="15" style={
            {
              fill:'lightyellow',
              stroke:'lightgray',
              filter: ''
            }} />
          {!this.state.hurt && <rect
            style={{fill:'gold',transform: `rotateY(${faceAttr[this.props.face||'front'].rotateY}deg) translateX(${faceAttr[this.props.face||'front'].translateX}%)`}}
            width="2" height="6" x="11" y="12" rx="1"
            >
              <animate
                id="h"
                attributeName="height"
                values="6;0;6"
                begin="5s;h.end+5s;"
                dur="0.2s"
                fill="freeze"/>
              <animate
                id="y"
                attributeName="y"
                values="12;18;12;"
                begin="h.begin"
                dur="0.2s"
                fill="freeze"/>
            </rect>}
          {!this.state.hurt && <rect
            style={{fill:'gold',transform: `rotateY(${faceAttr[this.props.face||'front'].rotateY}deg) translateX(${faceAttr[this.props.face||'front'].translateX}%)`}}
            width="2" height="6" x="17" y="12" rx="1"
            className="eye">
              <animate
                id="h"
                attributeName="height"
                values="6;0;6"
                begin="5s;h.end+5s;"
                dur="0.2s"
                fill="freeze"/>
              <animate
                id="y"
                attributeName="y"
                values="12;18;12;"
                begin="h.begin"
                dur="0.2s"
                fill="freeze"/>
              </rect>}
          {this.state.hurt && <polyline
            style={{strokeWidth:'1.5',stroke:'gold',fill:'transparent'}}
            points="10,12 13,15 10,18"
            ></polyline>}
          {this.state.hurt && <polyline
            style={{strokeWidth:'1.5',stroke:'gold',fill:'transparent'}}
            points="20,12 17,15 20,18"
            ></polyline>}
        </svg>
        {this.state.showShadow&&<div
          className={`run${this.dummy % 2} shadow`}
        ></div>}
      </div>
    )
  }
}

export default RoundFigure;
