import React, { ReactNodeArray } from 'react';
import Map from './Map';
import { MapFrame, IfShowInterface } from '../Maps/BaseInterface';
import { map, events } from '../Maps/res/plain1';
// import { map, events } from '../Maps/res/school';
// import { map, events } from '../Maps/res/underground';

import './PlayMode.scss';
import { Block } from '../Maps/Base';
import { clearSaveData, getAchievements, achievementsDetail } from '../Save/achievements';
import avatar from '../assets/images/mashroom.png';
import heart from '../assets/images/heart.png';
import harfHeart from '../assets/images/halfheart.png';
import akarin from '../assets/images/akkarin.jpg';
import Zawa from './Zawa';
import { deepCopy } from '../utils/tools';
import { EventsInterface, EventInterface } from '../Maps/res/ResInterface';
// import Toast from './Toast';

const SaveContext = React.createContext<any>({});

interface Props {
}
interface State {
  mapOffsetX: number;
  mapOffsetY: number;
  grid: boolean;
  curMap: MapFrame;
  moving: boolean;
  figureX: number;
  figureY: number;
  toastText: string;
  showToast: boolean;
  face: 'left' | 'right' | 'back' | 'front';
  events?: EventsInterface;
  mapCover?: string;
  mapBack?: string;
  ifShows?: {[index: string]: IfShowInterface},
  hurt: boolean;
  saveStatus: {[index:string]: any};
  eventCallBack?: EventInterface;
  bubbleText: string;
  loading: boolean;
}
class PlayMode extends React.Component<Props, State> {
  static contextType = SaveContext;
  moving = false;
  curKey: string | null = null;
  moveBoundle: (() => void) | null | 'busy' = null;
  curBoundleKey: string | null = null;
  mapMoveXCount: number = 0;
  mapMoveYCount: number = 0;
  mapRef: React.RefObject<Map>;
  state: State;
  constructor(props: Props, state: State) {
    super(props, state);
    this.mapRef = React.createRef();
    let bubbleText = 'WSAD移动，鼠标点击进行交互♪';
    this.state = {
      mapOffsetX: 0,
      mapOffsetY: 0,
      grid: false,
      curMap: map,
      events,
      moving: false,
      figureX: 5,
      figureY: 5,
      face: 'front',
      hurt: false,
      saveStatus: getAchievements(),
      bubbleText,
      loading: false,
      showToast: false,
      toastText: '',
    }
  }
  toggleSaveStatus = (obj: {[index:string]:any}) => {
    this.setState({
      saveStatus: obj
    })
  }
  resetSaveData = () => {
    this.setState({saveStatus: {}});
    clearSaveData();
  }
  moveFigure(key:string, x:number, y:number) {
    const pos:{
      x: number,
      y: number,
      mapX: number,
      mapY: number,
      face: 'front' | 'back' | 'left' | 'right'
    } = {
      x,
      y,
      mapX: this.state.mapOffsetX,
      mapY: this.state.mapOffsetY,
      face: 'front',
    };
    switch (key) {
      case 'w':
      case 'W':
        this.curKey = 'w';
        pos.face = 'back'
        if (
          y > 0
          && !this.checkBlocked(x, y - 1)) { 
          // this.setState({figureY: y - 1});
          pos.y -= 1;
          if (pos.mapY < 0 && pos.y + pos.mapY < 5) {
            pos.mapY+=1;
          }
        }
      break;
      case 's':
      case 'S':
        this.curKey = 's';
        pos.face = 'front';
        if (y < this.state.curMap.rowCount - 1
          && !this.checkBlocked(x, y + 1)) {
          // this.setState({figureY: y + 1});
          pos.y += 1;
          if (21 - pos.mapY < this.state.curMap.rowCount && 21 - pos.y + pos.mapY <= 5) {
            pos.mapY -= 1
          }
        }
      break;
      case 'a':
      case 'A':
        this.curKey = 'a';
        pos.face = 'left'
        if (x > 0 && !this.checkBlocked(x - 1, y)) {  
          // this.setState({figureX: x - 1});
          pos.x -= 1;
          if (pos.mapX < 0 && pos.x + pos.mapX < 5) {
            pos.mapX+=1;
          }
        }
      break;
      case 'd':
      case 'D':
        this.curKey = 'd';
        pos.face = 'right'
        if (x < this.state.curMap.columnCount -1
          && !this.checkBlocked(x + 1, y)) {
          // this.setState({figureX: x + 1});
          pos.x += 1;
          if (21 - pos.mapX < this.state.curMap.columnCount && 21 - pos.x + pos.mapX <= 5) {
            pos.mapX -= 1
          }
        }
      break;
    }
    return pos;
  }
  checkBlocked(x:number, y:number) {
    const mapData = this.state.curMap;
    const curBlock = mapData.blocks[y * mapData.columnCount + x];
    let flag = false;
    curBlock.units.forEach(item => {
      if (
        item.blocked
        && (!item.ifShow
        || (
          item.ifShow
          && this.state.ifShows
          && this.state.ifShows[item.ifShow]({
            achievements: this.state.saveStatus,
            roleX: this.state.figureX,
            roleY: this.state.figureY,
          })
        ))) {
          flag = true
        }
    })
    return flag;
  }
  handleMove(e: KeyboardEvent, x: number, y: number) {
    this.moving = true;
      this.setState(() => {
        const {x: figureX, y: figureY, mapX, mapY, face} = this.moveFigure(e.key, x, y);
        return {
          moving: true,
          figureX,
          figureY,
          mapOffsetX: mapX,
          mapOffsetY: mapY,
          face: face
        }
      }, () => {
        // this.moveFigure(e.key, x, y)
        setTimeout(()=>{
          this.setState({
            moving: false
          }, () => {
            this.moving = false;
            const state = this.state;
              const units = this.state.curMap.blocks[state.figureY * this.state.curMap.columnCount + state.figureX].units;
              const events = this.state.events;
              for (let item of units) {
                if (item.moveOn) {
                  if (events && events[item.moveOn]) {
                    const event = events[item.moveOn];
                    switch(event.type) {
                      case 'transport':
                        // console.log(event.action())
                        // const {map, events, x, y, offsetX, offsetY} = event.action();
                        const res = event.action();
                        console.log(res);
                        this.moveBoundle = null;
                        this.setState({loading: true});
                        // const {map, events, x, y, offsetX, offsetY} = res;
                        // console.log(map)
                        setTimeout(() => {
                          this.setState({loading: false});
                        }, 3000);
                        setTimeout(() => {
                          this.setState({
                            curMap: res.map,
                            events: res.events,
                            ifShows: res.ifShows,
                            mapCover: res.mapCover,
                            mapBack: res.mapBack,
                            figureX: res.x,
                            figureY: res.y,
                            mapOffsetX: res.offsetX,
                            mapOffsetY: res.offsetY,
                            face: res.faceTo,
                          }, () => {
                            let onInit;
                            if (res.map.onInit) {
                              onInit = res.events[res.map.onInit];
                            }
                            if (onInit) {
                              switch (onInit.type) {
                                case 'showText':
                                  if (onInit.action().then) {
                                    onInit.action().then((res: string) => {
                                      this.setState({
                                        bubbleText: res,
                                      });
                                    })
                                  } else {
                                    this.setState({
                                      bubbleText: onInit.action()
                                    })
                                  }
                                  break;
                                case 'figure':
                                  const res = onInit.action();
                                  console.log(res)
                                  const mapRef = this.mapRef.current;
                                  if (mapRef) {
                                    const figureRef = mapRef.ref.current;
                                    if (figureRef) {
                                      figureRef[res as keyof typeof figureRef]();
                                    }
                                  }
                                  break;
                              }
                            }
                          })
                        }, 500);
                        break;
                      case 'showText':
                        this.setState({
                          bubbleText: event.action(),
                        });
                        break;
                    }
                  }
                }
              }
            if (typeof this.moveBoundle === 'function') {
              this.moveBoundle();
            } else {
            }
          })
        }, 500)
      })
  }
  handleKeyPress = (e: KeyboardEvent) => {
    const x = this.state.figureX;
    const y = this.state.figureY;
    if (!this.moving) {
      // this.moveBoundle = 'busy';
      // setTimeout(() => {
      //   this.moveBoundle = null;
      // }, 450);
      this.handleMove(e, x, y);
    } else {
      if (this.moveBoundle !== 'busy') {
        this.moveBoundle = () => {
          this.handleMove(e, x, y);
          this.curBoundleKey = e.key;
          this.moveBoundle = null;
        }
      }
    }
  }
  handleKeyUp = (e:KeyboardEvent) => {
    if (this.curBoundleKey === e.key) {
      this.moveBoundle = null;
      this.curKey = null;
    }
  }
  changeToastStatus = (status: boolean) => {
    this.setState({
      showToast: status
    })
  }
  onBlockClick(block:Block) {
    const unit = block.units.find(item => {
      return item.click
    })
    if (unit && unit.click) {
      if (this.state.events) {
        const event = this.state.events[unit.click];
        const callBack = event.callBack ? this.state.events[event.callBack] : undefined;
        const res = event.action();
        switch(event.type) {
          case 'getItem':
            console.log(res)
            if (res.showToast && res.showToast.type==='getItem') {
              this.setState((state) => {
                const status = {}
                Object.assign(status, state.saveStatus, res.status)
                return {
                  toastText: `获得了《${res.showToast.name}》(点击右侧物品栏查看详情)`,
                  showToast: true,
                  saveStatus: deepCopy(status),
                  eventCallBack: callBack
                }
              })
            } else {
              this.setState((state) => {
                const status = Object.assign({}, state.saveStatus, res.sattus)
                return {
                  saveStatus: status,
                  eventCallBack: callBack
                }
              })
            }
            break;
          case 'getSkill':
          // const res = event.action();
          if (res.showToast && res.showToast.type==='getSkill') {
            this.setState((state) => {
              const status = {}
              Object.assign(status, state.saveStatus, res.status)
              return {
                toastText: `学会了《${res.showToast.name}》(点击右侧技能栏查看详情)`,
                showToast: true,
                saveStatus: deepCopy(status),
                eventCallBack: callBack
              }
            })
          } else {
            this.setState((state) => {
              const status = Object.assign({}, state.saveStatus, res.sattus)
              return {
                saveStatus: status,
                eventCallBack: callBack
              }
            })
          }
          break;
        }
      }
    }
  }
  handleEventCallBack = () => {
    const event = this.state.eventCallBack;
    if (event && this.state.events) {
      const callBack = event.callBack ? this.state.events[event.callBack] : undefined;
      const res = event.action();
      switch(event.type) {
        case 'getItem':
          console.log(res)
          if (res.showToast && res.showToast.type==='getItem') {
            this.setState((state) => {
              const status = {}
              Object.assign(status, state.saveStatus, res.status)
              return {
                toastText: `获得了《${res.showToast.name}》(点击右侧物品栏查看详情)`,
                showToast: true,
                saveStatus: deepCopy(status),
                eventCallBack: callBack
              }
            })
          } else {
            this.setState((state) => {
              const status = Object.assign({}, state.saveStatus, res.sattus)
              return {
                saveStatus: status,
                eventCallBack: callBack
              }
            })
          }
          break;
        case 'getSkill':
          // const res = event.action();
          if (res.showToast && res.showToast.type==='getSkill') {
            this.setState((state) => {
              const status = {}
              Object.assign(status, state.saveStatus, res.status)
              return {
                toastText: `学会了《${res.showToast.name}》(点击右侧技能栏查看详情)`,
                showToast: true,
                saveStatus: deepCopy(status),
                eventCallBack: callBack
              }
            })
          } else {
            this.setState((state) => {
              const status = Object.assign({}, state.saveStatus, res.sattus)
              return {
                saveStatus: status,
                eventCallBack: callBack
              }
            })
          }
          break;
        case 'showText':
          this.setState({
            bubbleText: res
          })
          break;
      }
    }
  }
  componentDidMount = () => {
    document.onkeydown = this.handleKeyPress;
    document.onkeyup = this.handleKeyUp;
    let onInit;
    if (map.onInit) {
      onInit = events[map.onInit];
    }
    if (onInit) {
      switch (onInit.type) {
        case 'showText':
          const bubbleText = onInit.action();
          if (bubbleText.then) {
            onInit.action().then((res: string) => {
              this.setState({
                bubbleText: res,
              });
            })
          } else {
            this.setState({
              bubbleText
            })
          }
          break;
        case 'figure':
          const res = onInit.action();
          const mapRef = this.mapRef.current;
          if (mapRef) {
            const figureRef = mapRef.ref.current;
            if (figureRef) {
              /// @ts-ignore
              console.log(figureRef[res])
              /// @ts-ignore
              figureRef[res]();
            }
          }
          break;
      }
    }
  }
  achieveClick = (detail?: React.ComponentClass) => {
    const curMap = this.mapRef.current;
    if (curMap && detail) {
      if (curMap.state.dialogVisiable) {
        curMap.changeDialogVisiable(false);
        setTimeout(() => {
          curMap.showDialog(React.createElement(detail))
        }, 700);
      } else {
        curMap.showDialog(React.createElement(detail))
      }
    }
  }
  render() {
    return (
      <SaveContext.Provider value={{
        saveStatus: this.state.saveStatus,
        toggleSaveStatus: this.toggleSaveStatus
      }}>
        <div id="play-mode">
          <div id="loading" className={`${this.state.loading?'loading':''}`}>
            <div className="loading-area">
              {this.state.loading&&<Zawa></Zawa>}
              <div className="font">{'Loading...'.split('').map((item, index) => {
                return <div className="loading-font" key={item+index} style={{
                  animationDelay: `${index*0.3}s`
                }}>{item}</div>
              })}</div>
            </div>
          </div>
          <div id="left">
            <div className="content">
              <div className="bubble-wrapper">
                <div className="top">
                  <div className="left-border">
                    <div className="col">
                      <div className="square empty"></div>
                      <div className="square empty"></div>
                      <div className="center solid"></div>
                      <div className="square empty"></div>
                      <div className="square empty"></div>
                    </div>
                    <div className="col">
                      <div className="square empty"></div>
                      <div className="square solid"></div>
                      <div className="center empty"></div>
                      <div className="square solid"></div>
                      <div className="square empty"></div>
                    </div>
                  </div>
                  <div className="bubble">
                      <span>{this.state.bubbleText.split('').map((font,index) => {
                        return (
                          <span key={font+index} className="bubble-font" style={{
                            animationDelay: `${(index * 0.1)}s`
                          }}>{font}</span>
                        )
                      })}</span>
                    </div>
                  <div className="right-border">
                    <div className="col">
                      <div className="square empty"></div>
                      <div className="square solid"></div>
                      <div className="center empty"></div>
                      <div className="square solid"></div>
                      <div className="square empty"></div>
                    </div>
                    <div className="col">
                      <div className="square empty"></div>
                      <div className="square empty"></div>
                      <div className="center solid"></div>
                      <div className="square empty"></div>
                      <div className="square empty"></div>
                    </div>
                  </div>
                </div>
                <div className="tail">
                <div className="flex">
                    <div className="square back"></div>
                    <div className="square back"></div>
                    <div className="square back"></div>
                    <div className="square back"></div>
                    <div className="square back"></div>
                    <div className="square back"></div>
                  </div>
                  <div className="flex">
                    <div className="square solid"></div>
                    <div className="square empty"></div>
                    <div className="square empty"></div>
                    <div className="square empty"></div>
                    <div className="square empty"></div>
                    <div className="square solid"></div>
                  </div>
                  <div className="flex">
                    <div className="square solid"></div>
                    <div className="square empty"></div>
                    <div className="square empty"></div>
                    <div className="square empty"></div>
                    <div className="square solid"></div>
                  </div>
                  <div className="flex">
                    <div className="square solid"></div>
                    <div className="square empty"></div>
                    <div className="square empty"></div>
                    <div className="square solid"></div>
                  </div>
                  <div className="flex">
                    <div className="square solid"></div>
                    <div className="square empty"></div>
                    <div className="square solid"></div>
                  </div>
                  <div className="flex">
                    <div className="square solid"></div>
                    <div className="square solid"></div>
                  </div>
                  <div className="flex">
                    <div className="square solid"></div>
                  </div>
                </div>
              </div>
              <img style={{marginTop: '-30px'}} alt="akarin" width="360" height="450" src={akarin} />
            </div>
          </div>
          <div id="center">
            {/* <Toast text="ceshi" /> */}
            <Map
              mapOffsetX={this.state.mapOffsetX}
              mapOffsetY={this.state.mapOffsetY}
              withGrid={this.state.grid}
              mapData={this.state.curMap}
              events={this.state.events}
              ifShows={this.state.ifShows}
              figureX={this.state.figureX}
              figureY={this.state.figureY}
              moving={this.state.moving}
              face={this.state.face}
              hurt={this.state.hurt}
              showToast={this.state.showToast}
              toastText={this.state.toastText}
              onBlockClick={(block)=>this.onBlockClick(block)}
              changeToastStatus={this.changeToastStatus}
              ref={this.mapRef}
              toastCallBack={this.handleEventCallBack}
              mapCover={this.state.mapCover}
              mapBack={this.state.mapBack}
              >
            </Map>
          </div>
          <div id="right">
            <div className="content">
              <SaveContext.Consumer>
                {
                  value => {
                    return (
                      <fieldset>
                        <div className="row role">
                          <img alt="avatar" src={avatar} width="64px" height="64px" />
                          <span>Player1</span>
                        </div>
                        <div className="row exp">
                          <div>
                            <span className="left">EXP:</span>
                            <span className="right">8753</span>
                          </div>
                        </div>
                        <div className="row next">
                          <div>
                            <span className="left">NEXT:</span>
                            <span className="right">65536</span>
                          </div>
                        </div>
                        <div className="row health">
                          <img alt="heart" className="heart" src={heart} width="32px" height="32px" />
                          <img alt="heart" className="heart" src={heart} width="32px" height="32px" />
                          <img alt="heart" className="heart" src={heart} width="32px" height="32px" />
                          <img alt="heart" className="heart" src={heart} width="32px" height="32px" />
                          <img alt="heart" className="heart" src={harfHeart} width="32px" height="32px" />
                        </div>
                        <div className="achievements-block">
                          <div className="achievements-list">
                            {/* {JSON.stringify(value)} */}
                            <div className="basket">
                              <h6>已获得物品</h6>
                              <div className="body">
                                {(()=>{
                                  const res:ReactNodeArray = [];
                                  achievementsDetail.items.forEach(item => {
                                    if (value.saveStatus[item.key]) {
                                      res.push(<span onClick={()=>this.achieveClick(item.detail)} key={item.key}>{item.name}</span>)
                                    }
                                  })
                                  if (res.length > 0) return res;
                                  return (<span className="holder">张开手，就获得了全世界</span>)
                                })()}
                              </div>
                            </div>
                            <div className="basket">
                              <h6>已获得技能</h6>
                              <div className="body">
                                {(()=>{
                                  const res:ReactNodeArray = [];
                                  achievementsDetail.skills.forEach(item => {
                                    if (value.saveStatus[item.key]) {
                                      res.push(<span onClick={()=>this.achieveClick(item.detail)} key={item.key}>{item.name}</span>)
                                    }
                                  })
                                  if (res.length > 0) return res;
                                  return (<span className="holder">人生充满了可能性</span>)
                                })()}
                              </div>
                            </div>
                          </div>
                          <button onClick={this.resetSaveData}>重置存档</button>
                        </div>
                      </fieldset>
                    )
                  }
                }
              </SaveContext.Consumer>
            </div>
          </div>
        </div>
      </SaveContext.Provider>
    )
  }
}

export default PlayMode;
